mapper.select:
SELECT 
FROM openplatform_v2_api_t


        AND id IN (
            SELECT resource_id FROM openplatform_v2_permission_t
            WHERE resource_type = 'api' AND category_id = #{categoryId}
        )


        AND status = #{status}


        AND (name_cn LIKE CONCAT('%', #{keyword}, '%')
             OR name_en LIKE CONCAT('%', #{keyword}, '%')
             OR id IN (
                 SELECT resource_id FROM openplatform_v2_permission_t
                 WHERE resource_type = 'api' AND scope LIKE CONCAT('%', #{keyword}, '%')
             ))


ORDER BY create_time DESC
LIMIT #{offset}, #{pageSize}

